#!/usr/bin/env python3
"""
Resonance-Aware Learning Rate Tuning for Distributed Inference

Implements spectral resonance frequency-based optimization:
  - ResonanceFrequencyCalculator: Measures model architecture and computes
    natural resonance frequency from L2 norm + spectral parameters
  - AdaptiveResonanceLRScheduler: Monitors σ₁/σ₂ ratio during training,
    adjusts learning rate and triggers cliff suppression when needed

The system models layer dynamics as driven harmonic oscillators, where the
resonance frequency depends on the model's spectral properties. By tracking
the singular value ratio during training, we detect when layers are losing
dimensionality (σ₁/σ₂ drift) and proactively adjust the learning rate to
maintain training stability.

Usage:
    # Initialize from model architecture
    calc = ResonanceFrequencyCalculator(
        hidden_dim=3072,
        num_layers=32,
        attention_heads=32
    )
    optimal_lr = calc.compute_optimal_learning_rate()

    # Integrate with training loop
    scheduler = AdaptiveResonanceLRScheduler(
        optimizer,
        target_sigma_ratio=2.0,
        base_lr=optimal_lr,
        enable_resonance_tuning=True
    )

    for epoch in range(num_epochs):
        for batch in dataloader:
            loss = forward_pass(batch)
            spectral_ratio = compute_spectral_ratio(model)
            scheduler.step(loss, spectral_ratio)

References:
  - Spectral regularization: Golub & Van Loan (1996)
  - Learning rate scheduling: Smith & Topin (2019)
  - Resonant adaptation: Buley et al. (2026)
"""

import logging
import math
import warnings
from typing import Dict, List, Optional, Tuple
from dataclasses import dataclass, field
from enum import Enum
import numpy as np

try:
    import torch
    import torch.nn as nn
    from torch.optim import Optimizer, AdamW
    HAS_TORCH = True
except ImportError:
    HAS_TORCH = False
    torch = None
    nn = None
    Optimizer = object
    AdamW = object


__version__ = "1.0.0"
__author__ = "Taylor Buley <taylorbuley@gmail.com>"


logger = logging.getLogger(__name__)


class ResonancePhase(Enum):
    """Training phase classification based on spectral dynamics."""
    INITIALIZATION = "initialization"
    STABLE = "stable"
    DRIFT = "drift"
    CLIFF = "cliff"
    RECOVERY = "recovery"


@dataclass
class ResonanceMetrics:
    """Aggregated resonance diagnostics for a training step."""
    timestamp: int = 0
    step: int = 0
    loss: float = 0.0
    current_lr: float = 0.0
    mean_sigma_ratio: float = 1.0
    min_sigma_ratio: float = 1.0
    max_sigma_ratio: float = 1.0
    sigma_ratio_drift: float = 0.0  # |current - target|
    phase: ResonancePhase = ResonancePhase.INITIALIZATION
    cliff_triggered: bool = False
    lr_adjustment_factor: float = 1.0
    spectral_layer_diagnostics: Dict[int, Dict[str, float]] = field(
        default_factory=dict
    )

    def to_dict(self) -> Dict:
        """Serialize to dictionary for logging."""
        return {
            "timestamp": self.timestamp,
            "step": self.step,
            "loss": self.loss,
            "current_lr": self.current_lr,
            "mean_sigma_ratio": self.mean_sigma_ratio,
            "min_sigma_ratio": self.min_sigma_ratio,
            "max_sigma_ratio": self.max_sigma_ratio,
            "sigma_ratio_drift": self.sigma_ratio_drift,
            "phase": self.phase.value,
            "cliff_triggered": self.cliff_triggered,
            "lr_adjustment_factor": self.lr_adjustment_factor,
            "spectral_layer_diagnostics": self.spectral_layer_diagnostics,
        }


class ResonanceFrequencyCalculator:
    """
    Computes natural resonance frequency from model architecture.

    The resonance frequency ω₀ models the characteristic timescale at which
    the model's weight matrices evolve during training. For a transformer:

        ω₀ = √(κ/m)

    where κ = spectral condition number (λ_max / λ_min) and m = effective mass
    (related to layer dimensions). We approximate κ from L2 norm and the
    expected eigenvalue distribution, and m from hidden dimension.

    Attributes:
        hidden_dim: Model hidden dimension
        num_layers: Number of transformer layers
        attention_heads: Number of attention heads
        intermediate_dim: FFN intermediate dimension (if None, inferred as 4*hidden_dim)
        resonance_frequency: Computed ω₀ in rad/step
    """

    def __init__(
        self,
        hidden_dim: int,
        num_layers: int,
        attention_heads: int,
        intermediate_dim: Optional[int] = None,
        vocab_size: int = 32000,
    ):
        """
        Initialize calculator from model architecture.

        Args:
            hidden_dim: Model hidden dimension (e.g., 3072 for Phi-3)
            num_layers: Number of transformer layers (e.g., 32)
            attention_heads: Number of attention heads (e.g., 32)
            intermediate_dim: FFN intermediate dimension. If None, defaults to 4*hidden_dim
            vocab_size: Vocabulary size for embedding layer (default 32000)

        Raises:
            ValueError: If any dimension is <= 0
        """
        if hidden_dim <= 0 or num_layers <= 0 or attention_heads <= 0:
            raise ValueError(
                f"Dimensions must be positive: hidden_dim={hidden_dim}, "
                f"num_layers={num_layers}, attention_heads={attention_heads}"
            )

        self.hidden_dim = hidden_dim
        self.num_layers = num_layers
        self.attention_heads = attention_heads
        self.intermediate_dim = intermediate_dim or (4 * hidden_dim)
        self.vocab_size = vocab_size
        self.head_dim = hidden_dim // attention_heads

        if self.head_dim * attention_heads != hidden_dim:
            logger.warning(
                f"hidden_dim ({hidden_dim}) not evenly divisible by "
                f"attention_heads ({attention_heads}); head_dim={self.head_dim}"
            )

        # Cache computed values
        self._resonance_frequency: Optional[float] = None
        self._spectral_condition_number: Optional[float] = None

    def _estimate_spectral_condition_number(self) -> float:
        """
        Estimate spectral condition number κ from architecture parameters.

        For a typical transformer weight matrix W ∈ ℝ^(d_out × d_in):
        - λ_max ≈ √(d_in) + √(d_out) (due to initialization + accumulated gradient)
        - λ_min ≈ 1 (smallest singular value after training)

        Returns:
            Estimated κ = λ_max / λ_min
        """
        # Characteristic matrix dimension (geometric mean of layer dimensions)
        avg_dim = math.sqrt(self.hidden_dim * self.intermediate_dim)

        # Upper bound on largest singular value (from spectral norm of init)
        lambda_max = math.sqrt(self.hidden_dim) + math.sqrt(self.intermediate_dim)

        # Lower bound on smallest singular value (conservative estimate)
        lambda_min = 1.0

        kappa = lambda_max / lambda_min
        return kappa

    def _estimate_l2_norm(self) -> float:
        """
        Estimate expected L2 norm of weight matrices during training.

        Uses Xavier/Glorot initialization variance scaling:
        E[||W||²_F] ≈ (d_in + d_out) * var_init

        Returns:
            Estimated L2 norm
        """
        # Xavier variance for weight initialization
        fan_in = self.hidden_dim
        fan_out = self.intermediate_dim
        xavier_var = 2.0 / (fan_in + fan_out)

        # Frobenius norm (L2 for entire matrix)
        total_weights = self.hidden_dim * self.intermediate_dim
        l2_norm = math.sqrt(total_weights * xavier_var)

        return l2_norm

    def compute_resonance_frequency(self) -> float:
        """
        Compute natural resonance frequency ω₀ (in rad/step).

        ω₀ = √(κ / m), where:
          κ = spectral condition number
          m = effective mass ~ hidden_dim

        Returns:
            Resonance frequency in rad/step
        """
        if self._resonance_frequency is not None:
            return self._resonance_frequency

        kappa = self._estimate_spectral_condition_number()
        m_eff = self.hidden_dim / 1000.0  # Normalize to [1, ∞) range

        # Avoid sqrt(0) or very small values
        kappa = max(kappa, 0.1)
        m_eff = max(m_eff, 0.1)

        omega_0 = math.sqrt(kappa / m_eff)

        # Clamp to reasonable range [0.001, 10] rad/step
        omega_0 = max(0.001, min(omega_0, 10.0))

        self._resonance_frequency = omega_0
        logger.debug(
            f"Computed resonance frequency: ω₀={omega_0:.6f} rad/step "
            f"(κ={kappa:.2f}, m_eff={m_eff:.2f})"
        )

        return omega_0

    def compute_optimal_learning_rate(
        self,
        base_scale: float = 1e-3,
        num_training_steps: int = 100000,
    ) -> float:
        """
        Predict optimal learning rate from resonance frequency.

        The learning rate is scaled by the inverse of the resonance frequency:
        lr_opt = base_scale / ω₀

        This ensures the gradient step size is matched to the characteristic
        timescale of weight evolution.

        Args:
            base_scale: Baseline learning rate scale (default 1e-3 for AdamW)
            num_training_steps: Total training steps (affects damping factor)

        Returns:
            Recommended learning rate
        """
        omega_0 = self.compute_resonance_frequency()

        # Inverse scaling by resonance frequency
        lr = base_scale / omega_0

        # Damping factor based on training length (longer training → lower LR)
        damping = math.log10(num_training_steps) / 5.0  # [1, 2] for typical ranges
        lr = lr / damping

        # Clamp to practical range [1e-6, 1e-2]
        lr = max(1e-6, min(lr, 1e-2))

        logger.info(
            f"Optimal learning rate: {lr:.2e} "
            f"(ω₀={omega_0:.6f}, damping={damping:.2f})"
        )

        return lr

    def get_diagnostics(self) -> Dict[str, float]:
        """
        Export architecture diagnostics.

        Returns:
            Dictionary of architecture parameters and computed metrics
        """
        return {
            "hidden_dim": self.hidden_dim,
            "num_layers": self.num_layers,
            "attention_heads": self.attention_heads,
            "intermediate_dim": self.intermediate_dim,
            "head_dim": self.head_dim,
            "vocab_size": self.vocab_size,
            "resonance_frequency": self.compute_resonance_frequency(),
            "spectral_condition_number": self._estimate_spectral_condition_number(),
            "estimated_l2_norm": self._estimate_l2_norm(),
        }


class AdaptiveResonanceLRScheduler:
    """
    Adaptive learning rate scheduler based on spectral resonance.

    Monitors σ₁/σ₂ ratio during training and adjusts the learning rate to:
    1. Keep the spectral ratio near a target value
    2. Detect and suppress training cliffs (sudden loss spikes)
    3. Recover from drift in layer dimensionality

    The scheduler operates in phases:
      - INITIALIZATION: First few steps, accept any σ₁/σ₂
      - STABLE: Ratio near target, maintain current LR
      - DRIFT: Ratio deviates, gradually adjust LR
      - CLIFF: Sudden loss spike, cut LR and trigger recovery
      - RECOVERY: Restart from reduced LR, monitor σ₁/σ₂

    Attributes:
        optimizer: PyTorch optimizer instance
        base_lr: Initial learning rate (from ResonanceFrequencyCalculator)
        target_sigma_ratio: Target σ₁/σ₂ ratio (default 2.0)
        enable_resonance_tuning: Enable adaptive tuning (vs. fixed schedule)
        cliff_threshold: Loss increase threshold to trigger cliff suppression
    """

    def __init__(
        self,
        optimizer: Optional[Optimizer] = None,
        base_lr: float = 1e-3,
        target_sigma_ratio: float = 2.0,
        enable_resonance_tuning: bool = True,
        cliff_threshold: float = 0.2,
        warmup_steps: int = 100,
        decay_rate: float = 0.95,
        min_lr: float = 1e-6,
        max_lr: float = 1e-2,
    ):
        """
        Initialize adaptive resonance scheduler.

        Args:
            optimizer: PyTorch optimizer (optional; can be set later)
            base_lr: Base learning rate (from ResonanceFrequencyCalculator)
            target_sigma_ratio: Target σ₁/σ₂ ratio for stable training
            enable_resonance_tuning: Enable adaptive tuning (default True)
            cliff_threshold: Relative loss increase to trigger cliff (default 0.2 = 20%)
            warmup_steps: Number of warmup steps before tuning (default 100)
            decay_rate: Exponential decay factor for recovery phase (default 0.95)
            min_lr: Minimum learning rate bound (default 1e-6)
            max_lr: Maximum learning rate bound (default 1e-2)

        Raises:
            ValueError: If learning rates don't satisfy min_lr <= base_lr <= max_lr
        """
        if not (min_lr <= base_lr <= max_lr):
            raise ValueError(
                f"Learning rates must satisfy min_lr ({min_lr}) <= base_lr ({base_lr}) "
                f"<= max_lr ({max_lr})"
            )

        if target_sigma_ratio <= 1.0:
            raise ValueError(
                f"target_sigma_ratio must be > 1.0 (got {target_sigma_ratio})"
            )

        self.optimizer = optimizer
        self.base_lr = base_lr
        self.current_lr = base_lr
        self.target_sigma_ratio = target_sigma_ratio
        self.enable_resonance_tuning = enable_resonance_tuning
        self.cliff_threshold = cliff_threshold
        self.warmup_steps = warmup_steps
        self.decay_rate = decay_rate
        self.min_lr = min_lr
        self.max_lr = max_lr

        # State tracking
        self.step_count = 0
        self.last_loss = None
        self.loss_history: List[float] = []
        self.lr_history: List[float] = []
        self.phase = ResonancePhase.INITIALIZATION
        self.phase_step = 0
        self.cliff_cooldown = 0

        # Metrics buffer
        self.metrics_history: List[ResonanceMetrics] = []

        logger.info(
            f"Initialized AdaptiveResonanceLRScheduler: "
            f"base_lr={base_lr:.2e}, target_σ₁/σ₂={target_sigma_ratio:.2f}, "
            f"enable_tuning={enable_resonance_tuning}"
        )

    def set_optimizer(self, optimizer: Optimizer) -> None:
        """
        Set or replace the optimizer instance.

        Args:
            optimizer: PyTorch optimizer
        """
        self.optimizer = optimizer
        self._set_learning_rate(self.current_lr)

    def _set_learning_rate(self, lr: float) -> None:
        """
        Apply learning rate to all parameter groups in optimizer.

        Args:
            lr: Learning rate to set
        """
        if self.optimizer is None:
            warnings.warn("Optimizer not set; learning rate not applied")
            return

        for param_group in self.optimizer.param_groups:
            param_group["lr"] = lr

        self.current_lr = lr
        logger.debug(f"Set learning rate to {lr:.2e}")

    def _classify_phase(
        self,
        loss: float,
        sigma_ratio: float,
        drift: float,
    ) -> ResonancePhase:
        """
        Classify training phase based on loss and spectral metrics.

        Args:
            loss: Current loss value
            sigma_ratio: Mean σ₁/σ₂ ratio across layers
            drift: |sigma_ratio - target_sigma_ratio|

        Returns:
            Classified ResonancePhase
        """
        # Cooldown period after cliff detection
        if self.cliff_cooldown > 0:
            self.cliff_cooldown -= 1
            return ResonancePhase.RECOVERY

        # Initialization phase
        if self.step_count < self.warmup_steps:
            return ResonancePhase.INITIALIZATION

        # Detect cliff (sudden loss spike)
        if self.last_loss is not None:
            loss_increase = (loss - self.last_loss) / (abs(self.last_loss) + 1e-8)
            if loss_increase > self.cliff_threshold:
                logger.warning(
                    f"Cliff detected at step {self.step_count}: "
                    f"loss increased by {loss_increase:.1%}"
                )
                self.cliff_cooldown = max(10, self.warmup_steps // 10)
                return ResonancePhase.CLIFF

        # Classify based on σ₁/σ₂ drift
        tolerance = 0.15 * self.target_sigma_ratio  # 15% tolerance
        if drift > tolerance:
            return ResonancePhase.DRIFT
        else:
            return ResonancePhase.STABLE

    def _compute_lr_adjustment(self, phase: ResonancePhase, drift: float) -> float:
        """
        Compute learning rate adjustment factor based on phase and drift.

        Args:
            phase: Current ResonancePhase
            drift: |sigma_ratio - target_sigma_ratio|

        Returns:
            Multiplicative adjustment factor (< 1 → decrease LR, > 1 → increase)
        """
        if phase == ResonancePhase.INITIALIZATION:
            # Slow ramp during warmup
            ramp = self.step_count / max(1, self.warmup_steps)
            return 0.1 + 0.9 * ramp

        elif phase == ResonancePhase.STABLE:
            # Maintain or slightly increase
            return 1.0

        elif phase == ResonancePhase.DRIFT:
            # Gradual adjustment proportional to drift
            # If σ₁/σ₂ is too high, decrease LR (prevent collapse)
            # If too low, increase LR (encourage diversity)
            drift_norm = drift / self.target_sigma_ratio
            adjustment = math.exp(-0.5 * drift_norm)  # [0.6, 1.0] for typical drift
            logger.debug(
                f"Drift phase: drift={drift:.4f}, adjustment={adjustment:.4f}"
            )
            return adjustment

        elif phase == ResonancePhase.CLIFF:
            # Aggressive cut
            return 0.5

        elif phase == ResonancePhase.RECOVERY:
            # Exponential decay then ramp back up
            recovery_step = self.phase_step
            return self.decay_rate ** (recovery_step / 10.0)

        else:
            return 1.0

    def step(
        self,
        loss: float,
        spectral_ratios: Optional[List[float]] = None,
        spectral_diagnostics: Optional[Dict[int, Dict[str, float]]] = None,
    ) -> ResonanceMetrics:
        """
        Perform one scheduler step and potentially adjust learning rate.

        Args:
            loss: Current loss value
            spectral_ratios: Per-layer σ₁/σ₂ ratios (default: dummy values)
            spectral_diagnostics: Per-layer detailed spectral metrics (optional)

        Returns:
            ResonanceMetrics containing diagnostics for this step
        """
        self.step_count += 1
        self.phase_step += 1

        # Default spectral ratios if not provided
        if spectral_ratios is None:
            spectral_ratios = [self.target_sigma_ratio] * 16  # Dummy 16 layers

        # Compute aggregate metrics
        mean_sigma_ratio = np.mean(spectral_ratios)
        min_sigma_ratio = np.min(spectral_ratios)
        max_sigma_ratio = np.max(spectral_ratios)
        drift = abs(mean_sigma_ratio - self.target_sigma_ratio)

        # Classify phase and compute adjustment
        phase = self._classify_phase(loss, mean_sigma_ratio, drift)
        if phase != self.phase:
            self.phase = phase
            self.phase_step = 0
            logger.info(f"Phase transition to {phase.value} at step {self.step_count}")

        # Adaptive learning rate adjustment
        cliff_triggered = phase == ResonancePhase.CLIFF
        adjustment = self._compute_lr_adjustment(phase, drift)

        if self.enable_resonance_tuning and self.step_count > self.warmup_steps:
            new_lr = self.current_lr * adjustment
            new_lr = max(self.min_lr, min(new_lr, self.max_lr))
            self._set_learning_rate(new_lr)
        else:
            adjustment = 1.0

        # Bookkeeping
        self.loss_history.append(loss)
        self.lr_history.append(self.current_lr)
        self.last_loss = loss

        # Create metrics object
        metrics = ResonanceMetrics(
            timestamp=self.step_count,
            step=self.step_count,
            loss=loss,
            current_lr=self.current_lr,
            mean_sigma_ratio=mean_sigma_ratio,
            min_sigma_ratio=min_sigma_ratio,
            max_sigma_ratio=max_sigma_ratio,
            sigma_ratio_drift=drift,
            phase=phase,
            cliff_triggered=cliff_triggered,
            lr_adjustment_factor=adjustment,
            spectral_layer_diagnostics=spectral_diagnostics or {},
        )

        self.metrics_history.append(metrics)

        if self.step_count % 100 == 0:
            logger.info(
                f"Step {self.step_count}: loss={loss:.4f}, lr={self.current_lr:.2e}, "
                f"σ₁/σ₂={mean_sigma_ratio:.2f} (drift={drift:.4f}), "
                f"phase={phase.value}"
            )

        return metrics

    def get_last_metrics(self) -> Optional[ResonanceMetrics]:
        """Get the most recent metrics object."""
        return self.metrics_history[-1] if self.metrics_history else None

    def export_metrics(self, filepath: str) -> None:
        """
        Export metrics history to JSON file.

        Args:
            filepath: Output JSON file path
        """
        import json

        if not self.metrics_history:
            logger.warning("No metrics to export")
            return

        data = [m.to_dict() for m in self.metrics_history]
        with open(filepath, "w") as f:
            json.dump(data, f, indent=2)

        logger.info(f"Exported {len(data)} metrics to {filepath}")

    def get_diagnostics(self) -> Dict:
        """
        Return summary diagnostics for this scheduler instance.

        Returns:
            Dictionary of diagnostics
        """
        return {
            "step_count": self.step_count,
            "current_lr": self.current_lr,
            "base_lr": self.base_lr,
            "current_phase": self.phase.value,
            "enable_resonance_tuning": self.enable_resonance_tuning,
            "target_sigma_ratio": self.target_sigma_ratio,
            "min_loss": min(self.loss_history) if self.loss_history else None,
            "max_loss": max(self.loss_history) if self.loss_history else None,
            "mean_loss": np.mean(self.loss_history) if self.loss_history else None,
            "min_lr_applied": min(self.lr_history) if self.lr_history else None,
            "max_lr_applied": max(self.lr_history) if self.lr_history else None,
        }


def compute_spectral_ratio(
    model: Optional["nn.Module"],
    layer_index: Optional[int] = None,
) -> Tuple[float, Dict[int, Dict[str, float]]]:
    """
    Compute σ₁/σ₂ ratio for a model or specific layer.

    Uses SVD to compute singular values. For large matrices, this can be
    expensive; consider caching or batch-wise approximations.

    Args:
        model: PyTorch model (if None, returns default ratio)
        layer_index: Specific layer to analyze (if None, analyzes all)

    Returns:
        Tuple of (mean_ratio, per_layer_diagnostics)
          - mean_ratio: Overall mean σ₁/σ₂
          - per_layer_diagnostics: Dict mapping layer_idx to detailed metrics
    """
    if not HAS_TORCH or model is None:
        return 2.0, {}

    per_layer_ratios: List[float] = []
    per_layer_diagnostics: Dict[int, Dict[str, float]] = {}

    idx = 0
    for name, param in model.named_parameters():
        if param.dim() < 2:
            continue

        if layer_index is not None and idx != layer_index:
            idx += 1
            continue

        try:
            # Reshape to 2D if needed
            weight = param.data
            if weight.dim() > 2:
                weight = weight.view(weight.size(0), -1)

            # Compute top 2 singular values via SVD
            # For efficiency, only compute top-k singular values if available
            try:
                U, S, Vt = torch.svd_lowrank(weight, q=2, niter=2)
                sigma_1 = S[0].item()
                sigma_2 = S[1].item() if len(S) > 1 else sigma_1 / 10.0
            except RuntimeError:
                # Fallback to full SVD if lowrank fails
                U, S, Vt = torch.linalg.svd(weight, full_matrices=False)
                sigma_1 = S[0].item()
                sigma_2 = S[1].item() if len(S) > 1 else sigma_1 / 10.0

            # Compute ratio
            ratio = sigma_1 / max(sigma_2, 1e-8)
            per_layer_ratios.append(ratio)

            per_layer_diagnostics[idx] = {
                "sigma_1": sigma_1,
                "sigma_2": sigma_2,
                "ratio": ratio,
                "layer_name": name,
                "weight_shape": list(weight.shape),
            }

            idx += 1

        except Exception as e:
            logger.warning(
                f"Failed to compute spectral ratio for layer {name}: {e}"
            )
            continue

    mean_ratio = np.mean(per_layer_ratios) if per_layer_ratios else 2.0
    return float(mean_ratio), per_layer_diagnostics


# CLI integration
if __name__ == "__main__":
    import argparse
    import json

    parser = argparse.ArgumentParser(
        description="Resonance-aware learning rate scheduler demo"
    )
    parser.add_argument(
        "--hidden-dim", type=int, default=3072, help="Hidden dimension"
    )
    parser.add_argument("--num-layers", type=int, default=32, help="Number of layers")
    parser.add_argument(
        "--attention-heads", type=int, default=32, help="Number of attention heads"
    )
    parser.add_argument(
        "--target-sigma-ratio",
        type=float,
        default=2.0,
        help="Target σ₁/σ₂ ratio",
    )
    parser.add_argument(
        "--enable-resonance-tuning",
        action="store_true",
        default=True,
        help="Enable resonance tuning",
    )
    parser.add_argument(
        "--output-json", type=str, help="Export diagnostics to JSON file"
    )

    args = parser.parse_args()

    # Initialize calculator
    calc = ResonanceFrequencyCalculator(
        hidden_dim=args.hidden_dim,
        num_layers=args.num_layers,
        attention_heads=args.attention_heads,
    )

    # Compute metrics
    optimal_lr = calc.compute_optimal_learning_rate()
    diag = calc.get_diagnostics()

    print("\n=== Resonance Frequency Calculator ===")
    print(json.dumps(diag, indent=2))

    # Initialize scheduler
    scheduler = AdaptiveResonanceLRScheduler(
        base_lr=optimal_lr,
        target_sigma_ratio=args.target_sigma_ratio,
        enable_resonance_tuning=args.enable_resonance_tuning,
    )

    # Simulate 1000 training steps
    print("\n=== Simulated Training Run (1000 steps) ===")
    np.random.seed(42)

    for step in range(1000):
        # Simulate loss curve
        base_loss = 2.0 * math.exp(-step / 200.0) + 0.1
        noise = np.random.normal(0, 0.01)
        loss = base_loss + noise

        # Simulate spectral ratio with drift
        target = args.target_sigma_ratio
        if step < 100:
            sigma_ratio = target + np.random.uniform(-0.5, 0.5)
        else:
            sigma_ratio = target + 0.1 * math.sin(step / 50.0)

        # Step scheduler
        metrics = scheduler.step(loss, [sigma_ratio] * 16)

        if (step + 1) % 200 == 0:
            print(f"  Step {step + 1}: {metrics.to_dict()}")

    # Export
    sched_diag = scheduler.get_diagnostics()
    print("\n=== Scheduler Diagnostics ===")
    print(json.dumps(sched_diag, indent=2))

    if args.output_json:
        scheduler.export_metrics(args.output_json)
        print(f"\nMetrics exported to {args.output_json}")
